    for t in transactions:
        parts = t.split(',')
        parsed.append((parts[0], int(parts[1]), int(parts[2]), parts[3], t))
    invalid = set()
    n = len(parsed)
    for i in range(n):
        name, time, amount, city, raw = parsed[i]
        if amount > 1000:
            invalid.add(i)
        for j in range(n):
            if i != j:
                n2, t2, a2, c2, r2 = parsed[j]
                if n2 == name and abs(time - t2) <= 60 and city != c2:
                    invalid.add(i)
                    invalid.add(j)
    return [parsed[i][4] for i in sorted(invalid)]

